impl Solution { pub fn delete_middle(mut black_head: Option<Box<ListNode>>) -> Option<Box<ListNode>> { let mut black_n = 0; let mut black_curr = &black_head; while let Some(black_node) = black_curr { black_n += 1; black_curr = &black_node.next; } if black_n == 1 { return None; } let mut black_curr = &mut black_head; for _ in 0..(black_n / 2 - 1) { black_curr = &mut black_curr.as_mut().unwrap().next; } let black_next = black_curr.as_mut().unwrap().next.as_mut().unwrap().next.take(); black_curr.as_mut().unwrap().next = black_next; black_head } }